  gwen: { diff: "EVEN", tone: "#e8b84b", tldr: "E her snips \u2014 fight when her W mist is down.", breakdown: "Build some MR, E (Counter Strike) dodges her Q-snip autos, and fight when her W is down.", dos: ["E to dodge her snip autos", "Fight when her W is down", "Build some MR"], donts: ["Fight inside her W mist", "Eat her Q snips", "Waste E early"], key: { slot: "W", name: "Hallowed Mist", cd: "16s", note: "She\u2019s safe inside it. Fight when down.", winT: "MIST DOWN", winS: "Q-E-W her." }, hold: "Hold E for her R + snip burst \u2014 Counter Strike dodges her autos and stuns her.", tip: "Bait her W mist down, then Q-E her in the open \u2014 her snip relies on staying untouched, which E denies.", win: "E her snips and fight off her mist." },
  irelia: { diff: "EVEN", tone: "#e8b84b", tldr: "E her engage \u2014 the stun stops her resets.", breakdown: "E (Counter Strike) dodges her reset autos and stuns, breaking her snowball. Out-scale her.", dos: ["E her engage autos", "Deny her Q reset targets", "Out-scale with R"], donts: ["Get E-stunned first", "Fight in a big wave", "Waste E early"], key: { slot: "E", name: "Flawless Duet (Stun)", cd: "18s", note: "Her engage CC. E the follow-up.", winT: "STUN DOWN", winS: "Q-E-W her." }, hold: "Hold E for her E-stun dive \u2014 Counter Strike dodges her reset autos and stuns her.", tip: "Pop E as she dives \u2014 Counter Strike dodges the autos she resets her Q off, killing her snowball.", win: "E her engage and out-scale her." },
