  pantheon: { diff: "TRICKY", tone: "#ff8b3d", tldr: "Survive his early \u2014 E his combo, then out-scale hard.", breakdown: "Pantheon\u2019s early combo hurts but he falls off. E his W-stun combo, survive, and out-scale.", dos: ["E his W-stun combo", "Respect his early all-in", "Out-scale with R"], donts: ["Trade into his W stun raw", "Sit low for his W execute", "Waste E early"], key: { slot: "W", name: "Shield Vault (Stun)", cd: "14s", note: "His all-in start. Bait it.", winT: "SHIELD VAULT DOWN", winS: "Q-E-W him." }, hold: "Hold E for his W-stun all-in \u2014 Counter Strike dodges the Q-auto follow-up and stuns him.", tip: "Pop E as his W-stun lands \u2014 you dodge his spear-auto burst and stun him, surviving to out-scale.", win: "E his early combo and out-scale hard." },
