  riven: { diff: "EVEN", tone: "#e8b84b", tldr: "E her combo \u2014 the stun stops her burst, out-scale her.", breakdown: "E (Counter Strike) dodges her empowered-auto combo and stuns. Bait her W, then commit.", dos: ["E her combo autos", "Bait her W stun", "Out-scale with R"], donts: ["Get W-stunned", "Fight her R burst raw", "Waste E early"], key: { slot: "W", name: "Ki Burst (Stun)", cd: "11s", note: "Her engage CC. Bait it.", winT: "KI BURST DOWN", winS: "Q-E-W her." }, hold: "Hold E for her empowered-combo burst \u2014 Counter Strike dodges her autos and stuns her mid-combo.", tip: "Pop E as she Q-W-autos in \u2014 her empowered autos are dodged and she\u2019s stunned mid-rotation.", win: "E her combo and out-scale her." },
